export interface ChangeOptions {
    remove?:boolean;
    removeTo?:string;
    removeToInclude?:string;
    removeAll?:boolean;
    leaveEmpty?:boolean;
    addView?:string|View|any;
    transitionClose?:string;
    transitionOpen?:string;
    pauseOptions?:PauseOptions;
}
export interface PauseOptions {
    alpha:number;
    duration:number;
    type:string;
}
export interface ViewOptions {
    id?:string;
    type?:string;
    assets?:any;
    category?:'gui'|'display'|'eye';
    soundSet?:string;
    ignoreSwipeDown?:boolean;
    transitionStageOnly?:boolean;
    pause?:boolean|PauseOptions;
    pauseParent?:boolean;
    pauseOptions?:PauseOptions;
}
